# ─── PBT (property-based) ──────────────────────────────────────────────────


@st.composite
def mention_dispatch_events(draw):
    return {
        "msg_id": draw(st.text(alphabet="abcdef0123456789", min_size=4, max_size=8)),
        "recipient": draw(st.sampled_from(["U2", "U3", "U4"])),
        "surfaces": draw(
            st.lists(
                st.sampled_from(["push", "in_app", "sound", "badge"]),
                min_size=1,
                max_size=4,
                unique=True,
            )
        ),
    }


@given(event=mention_dispatch_events())
@settings(max_examples=500, deadline=None)
def test_mention_pipeline_is_idempotent_on_repeated_dispatch_for_same_event(event):
    """Property: idempotent (REQ-001). For any single mention event,
    dispatching twice yields the same observable surface state as once —
    the pipeline MUST de-duplicate on (msg_id, recipient) pair."""
    state = {}
    DispatchMentionNotification.apply(event, state=state)
    snapshot_1 = dict(state)
    DispatchMentionNotification.apply(event, state=state)
    snapshot_2 = dict(state)
    assert snapshot_1 == snapshot_2


@given(
    dnd_active=st.booleans(),
    increments=st.lists(st.integers(min_value=1, max_value=10), min_size=1, max_size=20),
)
@settings(max_examples=500, deadline=None)
def test_unread_badge_count_is_monotonic_under_dnd(dnd_active, increments):
    """Property: monotonic (REQ-002, REQ-007). Across any sequence of mention
    increments while DND is active, unread_badge_count is non-decreasing —
    DND must never silently zero the badge."""
    badge = 0
    for inc in increments:
        prev = badge
        # Under DND, increment still applies (silence retains badge per REQ-002 glossary).
        if dnd_active:
            badge = UnreadBadgeSurface.increment_silent(badge, inc)
        else:
            badge = UnreadBadgeSurface.increment(badge, inc)
        assert badge >= prev


@given(
    msg_count=st.integers(min_value=1, max_value=20),
    dnd_active_throughout=st.just(True),
)
@settings(max_examples=500, deadline=None)
def test_dnd_silence_invariant_no_push_banner_sound_while_dnd_active(msg_count, dnd_active_throughout):
    """Property: invariant (REQ-002). For any number of mentions delivered
    while DND is active throughout, push / in-app banner / sound surfaces
    SHALL NOT fire for any of them."""
    target = make_member("U2", dnd={"manual_on": True, "schedule_window": None, "muted_channels": []})
    fired_surfaces = []
    for i in range(msg_count):
        msg = make_message(mention_ids=["U2"])
        result = DispatchMentionNotification(msg, [target], make_channel())
        fired_surfaces.append(result.get("surfaces_fired", []))

    flat = {s for run in fired_surfaces for s in run}
    assert "PushSurface" not in flat
    assert "InAppBannerSurface" not in flat
    assert "SoundSurface" not in flat


@given(
    non_member_count=st.integers(min_value=1, max_value=10),
)
@settings(max_examples=500, deadline=None)
def test_non_member_mention_invariant_zero_surfaces_fire(non_member_count):
    """Property: invariant (REQ-003). For any count of mentions targeting
    non-members of the channel, zero surfaces fire — across all of them."""
    channel = make_channel(members=["U1"])  # only U1 is a member
    fired_total = []
    for i in range(non_member_count):
        msg = make_message(mention_ids=[f"OUTSIDER_{i}"])
        target = make_member(f"OUTSIDER_{i}", channels=["C_OTHER"])
        result = DispatchMentionNotification(msg, [target], channel)
        fired_total.extend(result.get("surfaces_fired", []))
    assert fired_total == []


@given(self_mentions=st.integers(min_value=1, max_value=20))
@settings(max_examples=500, deadline=None)
def test_self_mention_invariant_zero_surfaces_fire(self_mentions):
    """Property: invariant (REQ-004). For any count of self-mentions, zero
    surfaces fire — author and recipient identity match SHALL suppress."""
    channel = make_channel()
    fired_total = []
    for i in range(self_mentions):
        msg = make_message(author="U2", mention_ids=["U2"])
        target = make_member("U2")
        result = DispatchMentionNotification(msg, [target], channel)
        fired_total.extend(result.get("surfaces_fired", []))
    assert fired_total == []
